package edu.rice.comp322.solutions;

import edu.rice.comp322.provided.trees.GList;
import edu.rice.comp322.provided.trees.Tree;

public class TreeSolutions {

    // @TODO Implement tree sum
    public static Integer problemOne(Tree<Integer> tree) {
        if (tree.isEmpty()) {
            return 0;
        } else {
            // Sum the current node's value with the sum of all children
            int currentValue = tree.value();
            int childrenSum = tree.children().foldLeft(0, (acc, child) -> acc + problemOne(child));
            return currentValue + childrenSum;
        }
    }

    // @TODO Implement tree sum using higher order list functions
    public static Integer problemTwo(Tree<Integer> tree) {
        if (tree.isEmpty()) {
            return 0;
        } else {
            // Use map to recursively sum each child, then fold to combine
            GList<Integer> childSums = tree.children().map(child -> problemTwo(child));
            int currentValue = tree.value();
            int totalChildSum = childSums.foldLeft(0, (acc, sum) -> acc + sum);
            return currentValue + totalChildSum;
        }
    }

    /*
     * Problem 3's solution should be written in the Tree.java class at line 118.
     */

    // @TODO Calculate the sum of the elements of the tree using tree fold
    public static Integer problemFour(Tree<Integer> tree) {
        // Use fold to sum all node values in the tree
        return tree.fold(0, (acc, value) -> acc + value);
    }

}

package edu.rice.comp322.solutions;

